@app.before_request
def load_redis_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data_json = redis_client.get(f"session:{session_id}")
        if session_data_json:
            try:
                session.update(json.loads(session_data_json))
            except json.JSONDecodeError:
                print(f"Error decoding session data for {session_id}")
                # Clear potentially corrupted session
                redis_client.delete(f"session:{session_id}")
                request.cookies.pop('session_id', None) # Remove invalid cookie
    if 'user_id' not in session:
        session['user_id'] = None # Ensure user_id is always present

@app.after_request
def save_redis_session(response):
    if session.get('user_id'): # Only save if a user is logged in
        session_id = request.cookies.get('session_id')
        if not session_id:
            # Generate a new session ID if one doesn't exist
            import uuid
            session_id = str(uuid.uuid4())
            response.set_cookie('session_id', session_id, httponly=True, secure=False, samesite='Lax', max_age=3600*24*7) # 7 days
        
        session_data = {k: v for k, v in session.items() if k != '_permanent'} # Flask's session adds _permanent, which we don't need to store
        redis_client.setex(f"session:{session_id}", 3600, json.dumps(session_data)) # Session expires in 1 hour
    else:
        # If user logs out or was never logged in, ensure session cookie is cleared
        session_id = request.cookies.get('session_id')
        if session_id:
            redis_client.delete(f"session:{session_id}")
            response.set_cookie('session_id', '', expires=0, httponly=True, secure=False, samesite='Lax') # Clear cookie

    return response

# --- Caching Decorator ---

def cache(key_prefix, timeout=300):
    """
    A caching decorator for Flask view functions or other functions.
    Caches the function's return value in Redis.
    The cache key is generated from key_prefix and function arguments.
    
    Args:
        key_prefix (str): A prefix for the Redis key to avoid collisions.
        timeout (int): The cache expiration time in seconds (default 300s = 5 minutes).
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Generate a unique cache key based on function name and its arguments
            # For Flask views, args might contain 'self' if it's a method or no relevant args
            # For simplicity, we use a combination of function name and JSON representation of args/kwargs.
            # In a real app, you might want a more sophisticated key generation (e.g., specific query params).
            
            # Remove Flask's request object from kwargs if present (it's not hashable)
            clean_kwargs = {k: v for k, v in kwargs.items() if k != 'request'}
            
            # Ensure args and kwargs are hashable/JSON serializable
            cache_key_parts = [func.__name__, json.dumps(args, sort_keys=True), json.dumps(clean_kwargs, sort_keys=True)]
            cache_key = f"cache:{key_prefix}:{hash(tuple(cache_key_parts))}"
            
            # Try to get data from cache
            cached_data = redis_client.get(cache_key)
            if cached_data:
                print(f"Cache hit for key: {cache_key}")
                return json.loads(cached_data)

            # If not in cache, execute the function
            print(f"Cache miss for key: {cache_key}. Executing function...")
            result = func(*args, **kwargs)

            # Store the result in cache
            # Ensure the result is JSON serializable
            try:
                redis_client.setex(cache_key, timeout, json.dumps(result))
            except TypeError as e:
                print(f"Warning: Could not cache result for {func.__name__}. Result not JSON serializable: {e}")

            return result
        return wrapper
    return decorator

