@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        user_id = request.form.get('user_id')
        user_data = _user_data_store.get(user_id)
        if user_data:
            session['user_id'] = user_id
            session['username'] = user_data['username']
            session['email'] = user_data['email']
            session['role'] = user_data['role']
            return jsonify({"message": f"User {user_data['username']} logged in successfully!"})
        return jsonify({"message": "Invalid user_id"}), 401
    
    return """
        <form method="post">
            <p>User ID (e.g., user1, user2): <input name="user_id"></p>
            <p><input type="submit" value="Login"></p>
        </form>
    """

@app.route('/logout')
def logout():
    session.clear() # Clears Flask's temporary session object
    return jsonify({"message": "Logged out successfully!"})

@app.route('/whoami')
def whoami():
    if session.get('user_id'):
        return jsonify({
            "user_id": session['user_id'],
            "username": session['username'],
            "email": session['email'],
            "role": session['role']
        })
    return jsonify({"message": "Not logged in"}), 401

